{{infobox
| bodyclass      = vcard
| child          = {{#if:{{{child|}}}{{{embed|}}}|yes}}

| title  = {{#if:{{{child|}}}{{{embed|}}}|{{{title|}}}}}
| aboveclass     = fn org
| abovestyle     = background-color: #abdb75; line-height: 140%;
| above          = {{if empty|{{{name|}}}|<includeonly>{{PAGENAMEBASE}}</includeonly> }}

| subheaderstyle = font-size: 110%
| subheader      = {{if empty|{{{alt_name|}}}|{{{other_name|}}}}}
| subheader2     = {{#if:{{{native_name|}}}|{{#if:{{{native_name_lang|}}}|<span class="nickname" lang="{{{native_name_lang}}}">}}{{{native_name}}}{{#if:{{{native_name_lang|}}}|</span>}}}}

| image1          = {{#invoke:InfoboxImage|InfoboxImage|image={{{logo|}}}|size={{{logo_size|}}}|upright={{{logo_upright|}}}|alt={{{logo_alt|}}}}}
| caption1        = {{{logo_caption|}}}

| image2          = {{#invoke:InfoboxImage|InfoboxImage|image={{{image|{{{photo|}}}}}}|size={{#switch:{{{image_size|{{{photo_width|}}}}}}
                     | frameless = frameless
                     | upright = frameless
                     | {{if empty|{{{image_size|}}}|{{{photo_width|}}} }}
                     }}|upright={{#ifeq:{{{image_size|{{{photo_width|}}}}}}|upright|0.75|{{{upright|}}}
                     }}|sizedefault=250px|maxsize=325px|alt={{{image_alt|{{{photo_alt|}}}}}} }}
| caption2        = {{{image_caption|{{{photo_caption|}}}}}}

| image3         = {{#if:{{{map|}}}
           | {{Location map|{{{map}}}
                     | border = infobox | float = center
                     | alt = {{{map_alt|}}}
                     | width = {{{map_width|}}}
                     | default_width = 250
                     | max_width = 272
                     | caption = {{{map_caption|}}}
                     | relief = {{{relief|}}}
                     | label = {{if empty|{{{label|}}}|{{{map_label|}}}}}
                     | position = {{if empty|{{{label_position|}}}|{{{map_label_position|}}}}}
                     | mark = {{{mark|}}}
                     | marksize = {{{mark_width|}}}
                     | coordinates = {{if empty|{{{coordinates|}}}|{{{coords|}}}}} }}
           | {{#invoke:InfoboxImage|InfoboxImage|image={{{map_image|{{{image_map|}}}}}}|size={{if empty|{{{map_size|}}}|{{{mapsize|}}}|{{{map_width|}}} }}|sizedefault=250px|maxsize=272px|alt={{{map_alt|}}}}}
           }}
| caption3 = {{#if:{{{map|}}} || {{{map_caption|}}} }}

| image4     = {{#invoke:Infobox mapframe|auto|mapframe-marker=park|mapframe-marker-color={{{mapframe-marker-color|#abdb75}}}|mapframe-frame-width=250|mapframe-wikidata={{{mapframe-wikidata|yes}}}|onByDefault={{#if:{{{map|}}}{{{map_image|}}}|no|yes}}}}
| caption4   = {{#invoke:Infobox mapframe|autocaption|onByDefault={{#if:{{{map|}}}{{{map_image|}}}|no|yes}}}}

| rowclass2      = category
| label2         = Type
| data2          = {{{type|}}}

| label3         = Motto
| data3          = {{{motto|{{{Motto|}}}}}}

| rowclass4      = label
| label4         = Location
| data4          = {{{location|}}}

| label5         = {{#if:{{{nearest_city|}}}|Nearest&nbsp;city
                   | {{#if:{{{nearest_town|}}}|Nearest&nbsp;town }}}}
| data5          = {{if empty|{{{nearest_city|}}}|{{{nearest_town|}}} }}

| label6         = [[Ordnance Survey National Grid|OS grid]]
| data6          = {{#if:{{{grid_ref_UK|}}}|{{gbm4ibx|{{{grid_ref_UK|}}}|name={{{name|{{PAGENAMEBASE}}}}} }}{{{grid_ref_UK_note|}}}}}

| label7         = [[Irish grid reference system|OSI/OSNI grid]]
| data7          = {{#if:{{{grid_ref_Ireland|}}}|{{iem4ibx|{{{grid_ref_Ireland|}}}|name={{{name|{{PAGENAMEBASE}}}}} }}{{{grid_ref_Ireland_note|}}}}}

| label8         = [[Geographic coordinate system|Coordinates]]
| data8          = {{#if:{{{coordinates|{{{coords|}}}}}}|{{#invoke:Coordinates|coordinsert|{{{coordinates|{{{coords|}}}}}}|type:landmark}}{{{coords_ref|}}}}}

