                   | {{#if:{{{manager|}}}|Managed&nbsp;by
                   | {{#if:{{{operator|}}}|Operated&nbsp;by}}}}}}
| data17         = {{if empty|{{{administrator|}}}|{{{manager|}}}|{{{operator|}}} }}

