| label24        = {{#if:{{{terrain|}}}|Terrain|Habitats}}
| data24         = {{#if:{{{terrain|}}}|{{{terrain}}}|{{{habitat|}}}}}

| label25        = Water
| data25         = {{{water|}}}

| label26        = {{#if:{{{vegetation|}}}|Vegetation|Plants}}
| data26         = {{#if:{{{vegetation|}}}|{{{vegetation}}}|{{{plants|}}}}}

| label27        = Species
| data27         = {{{species|}}}

| label28        = Collections
| data28         = {{{collections|}}}

| label30        = Designation
| data30         = {{{designation|}}}

| label32        = Threatened by
| data32         = {{{disturbance|}}}

| label34        = Budget
| data34         = {{{budget|}}}

| label35        = Parking
| data35         = {{{parking|}}}

| label36        = {{#if:{{{transport|}}}|Connecting transport|Public transit access}}
| data36         = {{#if:{{{transport|}}}|{{{transport}}}|{{{publictransit|}}}}}

| label37        = {{{free_label|}}}
| class37        = note
| data37         = {{{free_data|}}}

| label38        = {{#if:{{{facilities|}}}|Facilities|Other information}}
| data38         = {{#if:{{{facilities|}}}|{{{facilities|}}}|{{{other_info|}}}}}

| label39        = Website
